using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9: ZipArchiveEntry now respects the UTF-8 flag, which breaks
        // legacy consumers expecting Shift-JIS. Use explicit encoding to
        // suppress the UTF-8 flag and encode entry names in Shift-JIS.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");
        using var fs = new FileStream("data.zip", FileMode.Create);
        using var archive = new ZipArchive(fs, ZipArchiveMode.Create, leaveOpen: false, entryNameEncoding: shiftJis);
        archive.CreateEntry("Ńā¼ŃāØŃā╝Ńāł/µ£łµ¼Ī.csv");  // Japanese path
        archive.CreateEntry("donn├®es/r├®sum├®.txt"); // French accented
    }
}

// .NET 9: [FromKeyedServices] no longer falls back to non-keyed registrations.
// Register as a keyed service to match the controller's attribute.
